/* ================================================
   INDEX PAGE SPECIFIC STYLES
   ================================================ */

/* ================================================
   HERO / BANNER SECTION
   ================================================ */

.hero {
  height: 100vh;
  position: relative;
}

/* Dark gradient overlay */
.carousel-item::before {
  content: "";
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: linear-gradient(
    180deg,
    rgba(10, 22, 40, 0.4) 0%,
    rgba(10, 22, 40, 0.2) 50%,
    rgba(10, 22, 40, 0.6) 100%
  );
  z-index: 1;
}

.hero-content {
  z-index: 2;
  bottom: 35%;
  text-align: center;
  animation: fadeUp 1s ease;
}

.hero-content h1 {
  font-size: 52px;
  font-weight: 800;
  color: #fff;
  text-shadow: 0 4px 20px rgba(0, 0, 0, 0.5);
  letter-spacing: 1px;
}

.hero-content p {
  font-size: 20px;
  margin-top: 12px;
  color: #e0e8f0;
  font-weight: 300;
}

.hero-content .btn {
  padding: 14px 36px;
  font-size: 16px;
  font-weight: 600;
  border-radius: 50px;
  background: linear-gradient(135deg, #f0a500, #ffc947);
  border: none;
  color: #0a1628;
  transition: all 0.3s ease;
  letter-spacing: 0.5px;
}

.hero-content .btn:hover {
  transform: translateY(-4px);
  box-shadow: 0 12px 30px rgba(240, 165, 0, 0.4);
  background: linear-gradient(135deg, #ffc947, #f0a500);
}

/* Ken Burns for Carousel */
.carousel-item.active img {
  animation: kenBurnsHome 20s infinite alternate linear;
}

@keyframes kenBurnsHome {
  0% { transform: scale(1); }
  100% { transform: scale(1.15); }
}

@keyframes fadeUp {
  0% { opacity: 0; transform: translateY(30px); }
  100% { opacity: 1; transform: translateY(0); }
}

/* Carousel Controls */
.carousel-control-prev,
.carousel-control-next {
  width: 60px;
}

.carousel-control-prev-icon,
.carousel-control-next-icon {
  background-color: rgba(10, 22, 40, 0.5);
  border-radius: 50%;
  width: 50px;
  height: 50px;
  background-size: 50%;
  transition: all 0.3s ease;
  backdrop-filter: blur(4px);
}

.carousel-control-prev-icon:hover,
.carousel-control-next-icon:hover {
  background-color: rgba(0, 180, 216, 0.7);
}

/* Carousel Indicators */
.carousel-indicators button {
  width: 12px;
  height: 12px;
  border-radius: 50%;
  background-color: rgba(255, 255, 255, 0.5);
  border: 2px solid transparent;
  transition: all 0.3s ease;
}

.carousel-indicators button.active {
  background-color: #00b4d8;
  border-color: #ffffff;
  transform: scale(1.2);
}

.carousel-item img {
  height: 100vh;
  width: 100%;
  object-fit: cover;
}

/* Responsive Hero */
@media (max-width: 991px) {
  .carousel-item img { height: 70vh; }
  .hero-content h1 { font-size: 32px; }
  .hero-content p { font-size: 16px; }
  .hero-content { bottom: 30%; }
}

@media (max-width: 576px) {
  .carousel-item img { height: 50vh; }
  .hero-content h1 { font-size: 22px; }
  .hero-content p { font-size: 14px; }
  .hero-content { bottom: 25%; }
}

/* ================================================
   CONCISE CONTENT SECTION
   ================================================ */
.content-section {
    min-height: 80vh;
    padding: 5vh 2.5rem;
    display: flex;
    align-items: center;
    background: linear-gradient(135deg, var(--surface), var(--surface-alt));
}

/* Text */
.content-title {
    font-size: 2.8rem; /* was 34px → ~45px */
    line-height: 1.1;
    font-weight: 800;
    color: var(--primary);
    margin-bottom: 15px;
    position: relative;
}

/* underline effect */
.content-title::after {
    content: '';
    width: 60px;
    height: 4px;
    background: linear-gradient(90deg, var(--accent), var(--gold));
    display: block;
    margin-top: 10px;
    border-radius: 2px;
}

/* Description */
.content-desc {
    font-size: 1.1rem;
    color: var(--text-muted);
    line-height: 1.7;
    max-width: 500px;
}

/* Image */
.content-image img {
      max-width: 120%; /* Larger image */
    height: auto;
    width: auto;
    max-height: 500px;
    border-radius: 16px;
    box-shadow: var(--shadow-premium);
    transition: var(--transition-smooth);
}

/* Hover effect */
.content-image img:hover {
    transform: scale(1.05) rotate(-1deg);
}

/* Animation */
.content-text {
    animation: fadeLeft 1s ease forwards;
    font-size: 1.2em; /* 20% larger base */
}
.content-image {
    animation: fadeRight 1s ease forwards;
}

.content-text .btn-teal {
    padding: 16px 40px;
    font-size: 1.1rem;
}

@keyframes fadeLeft {
    from { opacity: 0; transform: translateX(-40px); }
    to { opacity: 1; transform: translateX(0); }
}

@keyframes fadeRight {
    from { opacity: 0; transform: translateX(40px); }
    to { opacity: 1; transform: translateX(0); }
}

/* Responsive */
@media (max-width: 768px) {
    .content-title {
        font-size: 26px;
        text-align: center;
    }

    .content-desc {
        text-align: center;
        margin: 0 auto;
    }

    .content-text {
        margin-bottom: 30px;
        text-align: center;
    }
}



/*--------------------------------------------------------------
# Testimonials Section
--------------------------------------------------------------*/
.testimonials .testimonial-wrap {
  padding-left: 50px;
}

.testimonials .testimonials-carousel,
.testimonials .testimonials-slider {
  overflow: hidden;
}

.testimonials .testimonial-item {
  background-color: var(--surface-color);
  border: 1px solid color-mix(in srgb, var(--default-color), transparent 90%);
  box-sizing: content-box;
  padding: 30px 30px 30px 60px;
  margin: 30px 15px;
  min-height: 200px;
  position: relative;
}

.testimonials .testimonial-item .testimonial-img {
  width: 90px;
  height: 90px;
  border-radius: 10px;
  border: 6px solid var(--background-color);
  position: absolute;
  left: -45px;
  object-fit: cover;
}

.testimonials .testimonial-item h3 {
  font-size: 18px;
  font-weight: bold;
  margin: 10px 0 5px 0;
}

.testimonials .testimonial-item h4 {
  color: color-mix(in srgb, var(--default-color), transparent 50%);
  font-size: 14px;
  margin: 0;
}

.testimonials .testimonial-item .stars {
  margin: 10px 0;
}

.testimonials .testimonial-item .stars i {
  color: #ffc107;
  margin: 0 1px;
}

.testimonials .testimonial-item .quote-icon-left,
.testimonials .testimonial-item .quote-icon-right {
  color: color-mix(in srgb, var(--accent-color), transparent 60%);
  font-size: 26px;
  line-height: 0;
}

.testimonials .testimonial-item .quote-icon-left {
  display: inline-block;
  left: -5px;
  position: relative;
}

.testimonials .testimonial-item .quote-icon-right {
  display: inline-block;
  right: -5px;
  position: relative;
  top: 10px;
  transform: scale(-1, -1);
}

.testimonials .testimonial-item p {
  font-style: italic;
  margin: 15px auto 15px auto;
}

.testimonials .swiper-wrapper {
  height: auto;
}

.testimonials .swiper-pagination {
  margin-top: 20px;
  position: relative;
}

.testimonials .swiper-pagination .swiper-pagination-bullet {
  width: 12px;
  height: 12px;
  background-color: var(--background-color);
  opacity: 1;
  border: 1px solid var(--accent-color);
}

.testimonials .swiper-pagination .swiper-pagination-bullet-active {
  background-color: var(--accent-color);
}

@media (max-width: 767px) {
  .testimonials .testimonial-wrap {
    padding-left: 0;
  }

  .testimonials .testimonials-carousel,
  .testimonials .testimonials-slider {
    overflow: hidden;
  }

  .testimonials .testimonial-item {
    padding: 30px;
    padding-top: 80px;
    margin: 15px;
  }

  .testimonials .testimonial-item .testimonial-img {
    position: absolute;
    left: 50%;
    transform: translateX(-50%);
    top: -45px;
    width: 90px;
    height: 90px;
  }
}
/* ================================================
   ACHIEVEMENTS SECTION
   ================================================ */
.achievements {
  padding: 70px 0;
  background: linear-gradient(180deg, #e8edf3 0%, #f0f4f8 100%);
}

/* Achievement Cards */
.achievement-card {
  position: relative;
  overflow: hidden;
  border-radius: 20px;
  box-shadow: var(--shadow-premium);
  transition: all 0.5s cubic-bezier(0.4, 0, 0.2, 1);
  border: 1px solid rgba(255, 255, 255, 0.3);
}

.achievement-card:hover {
  box-shadow: 0 20px 50px rgba(0, 180, 216, 0.25);
  transform: translateY(-10px) scale(1.02);
}

.achievement-card img {
  width: 100%;
  height: 420px;
  object-fit: cover;
  transition: all 0.7s ease;
}

.achievement-card:hover img {
  transform: scale(1.1);
}

/* Overlay */
.achievement-overlay {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: linear-gradient(
    180deg,
    rgba(10, 22, 40, 0.2) 0%,
    rgba(10, 22, 40, 0.7) 100%
  );
  display: flex;
  align-items: center;
  justify-content: center;
  opacity: 0;
  transition: all 0.4s ease;
}

.achievement-card:hover .achievement-overlay {
  opacity: 1;
}

.achievement-overlay .btn {
  border-radius: 50px;
  padding: 10px 30px;
  font-weight: 600;
  background: rgba(255, 255, 255, 0.95);
  color: #1e3a5f;
  border: none;
  transition: all 0.3s ease;
}

.achievement-overlay .btn:hover {
  background: #00b4d8;
  color: #fff;
  transform: scale(1.05);
}

/* ================================================
   IMAGE POPUP
   ================================================ */
.popup {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  display: none;
  justify-content: center;
  align-items: center;
  z-index: 9999;
  background: rgba(10, 22, 40, 0.85);
  backdrop-filter: blur(8px);
}

.popup img {
  max-width: 90%;
  max-height: 90%;
  border-radius: 12px;
  box-shadow: 0 20px 60px rgba(0, 0, 0, 0.5);
}

.close-btn {
  position: absolute;
  top: 20px;
  right: 20px;
  width: 44px;
  height: 44px;
  border: 2px solid rgba(255, 255, 255, 0.3);
  background: rgba(255, 255, 255, 0.1);
  backdrop-filter: blur(10px);
  border-radius: 50%;
  font-size: 18px;
  color: #fff;
  cursor: pointer;
  transition: all 0.3s ease;
}

.close-btn:hover {
  background: #00b4d8;
  border-color: #00b4d8;
  transform: rotate(90deg);
}

/* ================================================
   ASK US / CONTACT SECTION
   ================================================ */
.ask-us {
  padding: 90px 20px;
  background: linear-gradient(135deg, #0a1628 0%, #1e3a5f 50%, #2d5f8a 100%);
  color: #fff;
  text-align: center;
  position: relative;
  overflow: hidden;
}

/* Decorative glow */
.ask-us::before {
  content: '';
  position: absolute;
  top: -100px;
  right: -100px;
  width: 400px;
  height: 400px;
  background: radial-gradient(circle, rgba(0, 180, 216, 0.15) 0%, transparent 70%);
  border-radius: 50%;
}

.ask-us::after {
  content: '';
  position: absolute;
  bottom: -100px;
  left: -100px;
  width: 300px;
  height: 300px;
  background: radial-gradient(circle, rgba(240, 165, 0, 0.1) 0%, transparent 70%);
  border-radius: 50%;
}

.ask-us .container {
  max-width: 1200px;
  margin: 0 auto;
  position: relative;
  z-index: 1;
}

.ask-us .section-title {
  font-size: 42px;
  font-weight: 800;
  margin-bottom: 10px;
  background: linear-gradient(90deg, #ffffff, #00b4d8);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

.section-subtitle {
  font-size: 18px;
  margin-bottom: 50px;
  color: #b0c4d8;
  font-weight: 300;
}



/* Inquiry Form — Glassmorphism */
.inquiry-form {
  background: rgba(255, 255, 255, 0.08);
  padding: 35px;
  border-radius: 20px;
  backdrop-filter: blur(15px);
  border: 1px solid rgba(255, 255, 255, 0.12);
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.2);
}

.inquiry-form input,
.inquiry-form textarea {
  padding: 14px 20px;
  border-radius: 12px;
  border: 1px solid rgba(255, 255, 255, 0.15);
  font-size: 15px;
  font-family: 'Inter', sans-serif;
  background: rgba(255, 255, 255, 0.06);
  color: #fff;
  transition: all 0.3s ease;
}

.inquiry-form input::placeholder,
.inquiry-form textarea::placeholder {
  color: #8ca0b3;
}

.inquiry-form input:focus,
.inquiry-form textarea:focus {
  outline: none;
  border-color: #00b4d8;
  background: rgba(255, 255, 255, 0.1);
  box-shadow: 0 0 0 3px rgba(0, 180, 216, 0.15);
}

.inquiry-form textarea {
  resize: vertical;
  min-height: 120px;
}

.inquiry-form button {
  background: linear-gradient(135deg, #f0a500, #ffc947);
  color: #0a1628;
  padding: 15px;
  font-size: 16px;
  font-weight: 700;
  border: none;
  border-radius: 12px;
  cursor: pointer;
  transition: all 0.3s ease;
  font-family: 'Inter', sans-serif;
  letter-spacing: 0.5px;
}

.inquiry-form button:hover {
  background: linear-gradient(135deg, #ffc947, #f0a500);
  transform: translateY(-3px);
  box-shadow: 0 8px 25px rgba(240, 165, 0, 0.4);
}

/* Google Map */
.map-container {
  border-radius: 20px;
  overflow: hidden;
  box-shadow: 0 10px 40px rgba(0, 0, 0, 0.3);
  border: 2px solid rgba(255, 255, 255, 0.1);
}
